#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#define INF LONG_MAX
#define MAXN 200005
#define MAXM 200005
// Define the structure for a speedster
typedef struct {
    int u, v, t, s;
} Speedster;
// Define the structure for a vertex
typedef struct {
    int id;
    long long dist;
} Vertex;
// Compare function for the priority queue
int compare(const void *a, const void *b) {
    Vertex *va = (Vertex *)a;
    Vertex *vb = (Vertex *)b;
    return va->dist - vb->dist;
}
// Function to calculate the minimum time when a vertex is visited
void calculateMinTime(int N, int M, int **edges, Speedster *speedsters) {
    long long *minTime = (long long *)calloc(N, sizeof(long long));
    for (int i = 0; i < N; i++) {
        minTime[i] = INF;
    }
    // Process each speedster
    for (int i = 0; i < M; i++) {
        Speedster *speedster = &speedsters[i];
        int u = speedster->u - 1;
        int v = speedster->v - 1;
        int t = speedster->t;
        int s = speedster->s;
        // Calculate the time when the speedster reaches each vertex
        long long *time = (long long *)calloc(N, sizeof(long long));
        for (int j = 0; j < N; j++) {
            time[j] = INF;
        }
        time[u] = t;
        // Use a priority queue to process the vertices
        Vertex *queue = (Vertex *)calloc(N, sizeof(Vertex));
        int queueSize = 0;
        queue[queueSize].id = u;
        queue[queueSize].dist = time[u];
        queueSize++;
        while (queueSize > 0) {
            // Extract the vertex with the minimum distance
            Vertex minVertex = queue[0];
            for (int j = 1; j < queueSize; j++) {
                if (queue[j].dist < minVertex.dist) {
                    minVertex = queue[j];
                }
            }
            // Remove the extracted vertex from the queue
            for (int j = 0; j < queueSize; j++) {
                if (queue[j].id == minVertex.id) {
                    for (int k = j; k < queueSize - 1; k++) {
                        queue[k] = queue[k + 1];
                    }
                    queueSize--;
                    break;
                }
            }
            // Update the distances of the adjacent vertices
            for (int j = 0; j < N - 1; j++) {
                int x = edges[j][0] - 1;
                int y = edges[j][1] - 1;
                int w = edges[j][2];
                if (x == minVertex.id) {
                    long long newTime = minVertex.dist + (long long)w / s;
                    if (newTime < time[y]) {
                        time[y] = newTime;
                        queue[queueSize].id = y;
                        queue[queueSize].dist = newTime;
                        queueSize++;
                    }
                } else if (y == minVertex.id) {
                    long long newTime = minVertex.dist + (long long)w / s;
                    if (newTime < time[x]) {
                        time[x] = newTime;
                        queue[queueSize].id = x;
                        queue[queueSize].dist = newTime;
                        queueSize++;
                    }
                }
            }
        }
        // Update the minimum time when each vertex is visited
        for (int j = 0; j < N; j++) {
            if (time[j] < minTime[j]) {
                minTime[j] = time[j];
            }
        }
        free(time);
        free(queue);
    }
    // Print the minimum time when each vertex is visited
    for (int i = 0; i < N; i++) {
        if (minTime[i] == INF) {
            printf("-1\n");
        } else {
            printf("%lld\n", minTime[i]);
        }
    }
    free(minTime);
}
int main() {
    int T;
    scanf("%d", &T);
    for (int i = 0; i < T; i++) {
        int N;
        scanf("%d", &N);
        int **edges = (int **)calloc(N - 1, sizeof(int *));
        for (int j = 0; j < N - 1; j++) {
            edges[j] = (int *)calloc(3, sizeof(int));
            scanf("%d %d %d", &edges[j][0], &edges[j][1], &edges[j][2]);
        }
        int M;
        scanf("%d", &M);
        Speedster *speedsters = (Speedster *)calloc(M, sizeof(Speedster));
        for (int j = 0; j < M; j++) {
            scanf("%d %d %d %d", &speedsters[j].u, &speedsters[j].v, &speedsters[j].t, &speedsters[j].s);
        }
        calculateMinTime(N, M, edges, speedsters);
        for (int j = 0; j < N - 1; j++) {
            free(edges[j]);
        }
        free(edges);
        free(speedsters);
    }
    return 0;
}

