// COMPLETE, COMPILABLE C++ code
#include <iostream>
#include <vector>
#include <queue>
#include <limits>
using namespace std;
#define INF LONG_MAX
#define MAXN 200005
#define MAXM 200005
// Define the structure for a speedster
struct Speedster {
    int u, v, t, s;
};
// Define the structure for a vertex
struct Vertex {
    int id;
    long long dist;
    bool operator<(const Vertex &other) const {
        return dist > other.dist;
    }
};
// Function to calculate the minimum time when a vertex is visited
void calculateMinTime(int N, int M, vector<vector<int>> &edges, Speedster *speedsters) {
    vector<long long> minTime(N, INF);
    // Process each speedster
    for (int i = 0; i < M; i++) {
        Speedster *speedster = &speedsters[i];
        int u = speedster->u - 1;
        int v = speedster->v - 1;
        int t = speedster->t;
        int s = speedster->s;
        // Calculate the time when the speedster reaches each vertex
        vector<long long> time(N, INF);
        time[u] = t;
        // Use a priority queue to process the vertices
        priority_queue<Vertex> queue;
        queue.push({u, time[u]});
        while (!queue.empty()) {
            Vertex minVertex = queue.top();
            queue.pop();
            // Update the distances of the adjacent vertices
            for (int j = 0; j < N - 1; j++) {
                int x = edges[j][0] - 1;
                int y = edges[j][1] - 1;
                int w = edges[j][2];
                if (x == minVertex.id) {
                    long long newTime = minVertex.dist + (long long)w / s;
                    if (newTime < time[y]) {
                        time[y] = newTime;
                        queue.push({y, newTime});
                    }
                } else if (y == minVertex.id) {
                    long long newTime = minVertex.dist + (long long)w / s;
                    if (newTime < time[x]) {
                        time[x] = newTime;
                        queue.push({x, newTime});
                    }
                }
            }
        }
        // Update the minimum time when each vertex is visited
        for (int j = 0; j < N; j++) {
            if (time[j] < minTime[j]) {
                minTime[j] = time[j];
            }
        }
    }
    // Print the minimum time when each vertex is visited
    for (int i = 0; i < N; i++) {
        if (minTime[i] == INF) {
            cout << -1 << endl;
        } else {
            cout << minTime[i] << endl;
        }
    }
}
int main() {
    int T;
    cin >> T;
    for (int i = 0; i < T; i++) {
        int N;
        cin >> N;
        vector<vector<int>> edges(N - 1, vector<int>(3));
        for (int j = 0; j < N - 1; j++) {
            cin >> edges[j][0] >> edges[j][1] >> edges[j][2];
        }
        int M;
        cin >> M;
        Speedster *speedsters = new Speedster[M];
        for (int j = 0; j < M; j++) {
            cin >> speedsters[j].u >> speedsters[j].v >> speedsters[j].t >> speedsters[j].s;
        }
        calculateMinTime(N, M, edges, speedsters);
        delete[] speedsters;
    }
    return 0;
}
